unsavedChanges.customExample:
import {
  attachPageLeaveWarning,
  createUnsavedChangesTracker,
  shouldActivatePageLeaveWarning,
} from '@mushket-co/block-builder/core'

const tracker = createUnsavedChangesTracker(initialBlocks)
let detachGuard = () => {}

function syncPageLeaveGuard(isEdit, getBlocks) {
  detachGuard()
  detachGuard = () => {}

  if (!shouldActivatePageLeaveWarning({ warnOnPageLeave: true, isEdit })) {
    return
  }

  detachGuard = attachPageLeaveWarning(() => tracker.isDirty(getBlocks()))
}

async function handleSave(blocks) {
  const ok = await saveToApi(blocks)
  if (ok) {
    tracker.resetBaseline(blocks)
    syncPageLeaveGuard(true, () => blocks)
  }
}

// при mount / смене isEdit или блоков:
syncPageLeaveGuard(isEdit, () => blockBuilder.getAllBlocks())

// при unmount:
detachGuard()

